commits.content:
/* Файл: CustomArrows.module.css */

/* Стили для родительского контейнера слайдера (если он находится в том же файле, где и слайдер) */
/* Если родительский контейнер в другом файле, его стили нужно будет задать там */
.mySliderWrapper { /* Пример класса для родителя */
  position: relative;
  width: 80%;
  margin: 0 auto;
  overflow: hidden;
}

/* Стили для самих контейнеров стрелок */
.customNextArrowContainer,
.customPrevArrowContainer {
  /* Эти стили уже заданы в JSX, но можно их продублировать или уточнить здесь */
  opacity: 1 !important; /* Переопределяем возможную прозрачность */
}

/* --- Создание формы стрелки "Вперед" (right arrow) --- */

/* Основная линия стрелки "Вперед" */
.customNextArrowContainer::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 30px;
  height: 30px;
  border-top: 3px solid #FF8C00;
  border-right: 3px solid #FF8C00;
  transform: translate(-50%, -50%) rotate(45deg);
  transform-origin: center center;
}

/* "Острие" стрелки "Вперед" */
.customNextArrowContainer::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 15px;
  height: 15px;
  border-top: 3px solid #FF8C00;
  border-right: 3px solid #FF8C00;
  transform: translate(-50%, -50%) rotate(45deg);
  transform-origin: center center;
  margin-left: 15px; /* Примерный сдвиг */
}

/* --- Создание формы стрелки "Назад" (left arrow) --- */

/* Основная линия стрелки "Назад" */
.customPrevArrowContainer::before {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 30px;
  height: 30px;
  border-top: 3px solid #FF8C00;
  border-right: 3px solid #FF8C00;
  transform: translate(-50%, -50%) rotate(-135deg);
  transform-origin: center center;
}

/* "Острие" стрелки "Назад" */
.customPrevArrowContainer::after {
  content: '';
  position: absolute;
  top: 50%;
  left: 50%;
  width: 15px;
  height: 15px;
  border-top: 3px solid #FF8C00;
  border-right: 3px solid #FF8C00;
  transform: translate(-50%, -50%) rotate(-135deg);
  transform-origin: center center;
  margin-left: 15px; /* Примерный сдвиг */
}

/* Дополнительные стили для наведения */
.customNextArrowContainer:hover::before,
.customNextArrowContainer:hover::after,
.customPrevArrowContainer:hover::before,
.customPrevArrowContainer:hover::after {
  border-color: #FFA500; /* Более яркий оранжевый при наведении */
}
